fun reverseTransformations(inBitmap: Bitmap, exifData: ExifData): Bitmap {
    // Short circuit if there are no transformations to apply.
    if (!exifData.isFlipped && !exifData.isRotated) {
        return inBitmap
    }

    val matrix = Matrix()
    val centerX = inBitmap.width / 2f
    val centerY = inBitmap.height / 2f
    if (exifData.isFlipped) {
        matrix.postScale(-1f, 1f, centerX, centerY)
    }
    if (exifData.isRotated) {
        matrix.postRotate(exifData.rotationDegrees.toFloat(), centerX, centerY)
    }

    val rect = RectF(0f, 0f, inBitmap.width.toFloat(), inBitmap.height.toFloat())
    matrix.mapRect(rect)
    if (rect.left != 0f || rect.top != 0f) {
        matrix.postTranslate(-rect.left, -rect.top)
    }

    val outBitmap = if (exifData.isSwapped) {
        createBitmap(inBitmap.height, inBitmap.width, inBitmap.safeConfig)
    } else {
        createBitmap(inBitmap.width, inBitmap.height, inBitmap.safeConfig)
    }

    outBitmap.applyCanvas {
        drawBitmap(inBitmap, matrix, paint)
    }
    inBitmap.recycle()
    return outBitmap
}

internal actual fun convertImageToBitmap(
    image: Image,
    options: Options,
    transformations: List<Transformation>,
    logger: Logger?,
): Bitmap {
    // Fast path: return the existing bitmap.
    if (image is BitmapImage) {
        val bitmap = image.bitmap
        val config = bitmap.safeConfig
        if (config in VALID_TRANSFORMATION_CONFIGS) {
            return bitmap
        } else {
            logger?.log(TAG, Logger.Level.Info) {
                "Converting bitmap with config $config " +
                    "to apply transformations: $transformations."
            }
        }
    } else {
        logger?.log(TAG, Logger.Level.Info) {
            "Converting image of type ${image::class.qualifiedName} " +
                "to apply transformations: $transformations."
        }
    }

    // Slow path: draw the drawable on a canvas.
    return DrawableUtils.convertToBitmap(
        drawable = image.asDrawable(options.context.resources),
        config = options.bitmapConfig,
        size = options.size,
        scale = options.scale,
        maxSize = options.maxBitmapSize,
        allowInexactSize = options.precision == Precision.INEXACT,
    )
}

override suspend fun size(): Size {
    // Fast path: the view is already measured.
    getSize()?.let { return it }

    // Slow path: wait for the view to be measured.
    return suspendCancellableCoroutine { continuation ->
        val viewTreeObserver = view.viewTreeObserver

        val preDrawListener = object : OnPreDrawListener {
            private var isResumed = false

            override fun onPreDraw(): Boolean {
                val size = getSize()
                if (size != null) {
                    viewTreeObserver.removePreDrawListenerSafe(this)

                    if (!isResumed) {
                        isResumed = true
                        continuation.resume(size)
                    }
                }
                return true
            }
        }

        viewTreeObserver.addOnPreDrawListener(preDrawListener)

        continuation.invokeOnCancellation {
            viewTreeObserver.removePreDrawListenerSafe(preDrawListener)
        }
    }
}

override fun draw(canvas: Canvas) {
    if (state == STATE_START) {
        start?.apply {
            alpha = maxAlpha
            canvas.withSave { draw(canvas) }
        }
        return
    }

    if (state == STATE_DONE) {
        end?.apply {
            alpha = maxAlpha
            canvas.withSave { draw(canvas) }
        }
        return
    }

    val percent = (SystemClock.uptimeMillis() - startTimeMillis) / durationMillis.toDouble()
    val endAlpha = (percent.coerceIn(0.0, 1.0) * maxAlpha).toInt()
    val startAlpha = if (fadeStart) maxAlpha - endAlpha else maxAlpha
    val isDone = percent >= 1.0

    // Draw the start drawable.
    if (!isDone) {
        start?.apply {
            alpha = startAlpha
            canvas.withSave { draw(canvas) }
        }
    }

    // Draw the end drawable.
    end?.apply {
        alpha = endAlpha
        canvas.withSave { draw(canvas) }
    }

    if (isDone) {
        markDone()
    } else {
        invalidateSelf()
    }
}

private fun readJournal() {
    fileSystem.read(journalFile) {
        val magic = readUtf8LineStrict()
        val version = readUtf8LineStrict()
        val appVersionString = readUtf8LineStrict()
        val valueCountString = readUtf8LineStrict()
        val blank = readUtf8LineStrict()

        if (MAGIC != magic ||
            VERSION != version ||
            appVersion.toString() != appVersionString ||
            valueCount.toString() != valueCountString ||
            blank.isNotEmpty()
        ) {
            throw IOException(
                "unexpected journal header: " +
                "[$magic, $version, $appVersionString, $valueCountString, $blank]",
            )
        }

        var lineCount = 0
        while (true) {
            try {
                readJournalLine(readUtf8LineStrict())
                lineCount++
            } catch (_: EOFException) {
                break // End of journal.
            }
        }

        operationsSinceRewrite = lineCount - lruEntries.size

        // If we ended on a truncated line, rebuild the journal before appending to it.
        if (!exhausted()) {
            writeJournal()
        } else {
            journalWriter = newJournalWriter()
        }
    }
}

private fun readJournalLine(line: String) {
    val firstSpace = line.indexOf(' ')
    if (firstSpace == -1) throw IOException("unexpected journal line: $line")

    val keyBegin = firstSpace + 1
    val secondSpace = line.indexOf(' ', keyBegin)
    val key: String
    if (secondSpace == -1) {
        key = line.substring(keyBegin)
        if (firstSpace == REMOVE.length && line.startsWith(REMOVE)) {
            lruEntries.remove(key)
            return
        }
    } else {
        key = line.substring(keyBegin, secondSpace)
    }

    val entry = lruEntries.getOrPut(key) { Entry(key) }
    when {
        secondSpace != -1 && firstSpace == CLEAN.length && line.startsWith(CLEAN) -> {
            val parts = line.substring(secondSpace + 1).split(' ')
            entry.readable = true
            entry.currentEditor = null
            entry.setLengths(parts)
        }
        secondSpace == -1 && firstSpace == DIRTY.length && line.startsWith(DIRTY) -> {
            entry.currentEditor = Editor(entry)
        }
        secondSpace == -1 && firstSpace == READ.length && line.startsWith(READ) -> {
            // This work was already done by calling lruEntries.get().
        }
        else -> throw IOException("unexpected journal line: $line")
    }
}

private suspend fun fetch(
    components: ComponentRegistry,
    request: ImageRequest,
    mappedData: Any,
    options: Options,
    eventListener: EventListener,
): FetchResult {
    val fetchResult: FetchResult
    var searchIndex = 0
    while (true) {
        val pair = components.newFetcher(mappedData, options, imageLoader, searchIndex)
        checkNotNull(pair) { "Unable to create a fetcher that supports: $mappedData" }
        val fetcher = pair.first
        searchIndex = pair.second + 1

        eventListener.fetchStart(request, fetcher, options)
        val result = fetcher.fetch()
        try {
            eventListener.fetchEnd(request, fetcher, options, result)
        } catch (throwable: Throwable) {
            // Ensure the source is closed if an exception occurs before returning the result.
            (result as? SourceFetchResult)?.source?.closeQuietly()
            throw throwable
        }

        if (result != null) {
            fetchResult = result
            break
        }
    }
    return fetchResult
}

internal suspend fun transform(
    result: ExecuteResult,
    request: ImageRequest,
    options: Options,
    eventListener: EventListener,
    logger: Logger?,
): ExecuteResult {
    val transformations = request.transformations
    if (transformations.isEmpty()) {
        return result
    }

    // Skip the transformations as converting to a bitmap is disabled.
    val image = result.image
    if (image !is BitmapImage && !request.allowConversionToBitmap) {
        logger?.log(TAG, Logger.Level.Info) {
            val type = result.image::class.simpleName
            "allowConversionToBitmap=false, skipping transformations for type $type."
        }
        return result
    }

    // Apply the transformations.
    val input = convertImageToBitmap(image, options, transformations, logger)
    eventListener.transformStart(request, input)
    val output = transformations.foldIndices(input) { bitmap, transformation ->
        transformation.transform(bitmap, options.size).also { coroutineContext.ensureActive() }
    }
    eventListener.transformEnd(request, output)
    return result.copy(image = output.asImage())
}

fun newCacheKey(
    request: ImageRequest,
    mappedData: Any,
    options: Options,
    eventListener: EventListener,
): MemoryCache.Key? {
    // Fast path: read and write are both disabled.
    if (request.memoryCachePolicy == CachePolicy.DISABLED) {
        return null
    }

    // Fast path: an explicit memory cache key has been set.
    if (request.memoryCacheKey != null) {
        return MemoryCache.Key(request.memoryCacheKey, request.memoryCacheKeyExtras)
    }

    // Slow path: create a new memory cache key.
    eventListener.keyStart(request, mappedData)
    val key = imageLoader.components.key(mappedData, options, logger, TAG)
    eventListener.keyEnd(request, key)
    if (key == null) {
        return null
    }

    // Else, create a memory cache key with all extras.
    if (request.transformations.isNotEmpty()) {
        val extras = request.memoryCacheKeyExtras.toMutableMap()
        extras[EXTRA_SIZE] = options.size.toString()
        return MemoryCache.Key(key, extras)
    } else {
        return MemoryCache.Key(key, request.memoryCacheKeyExtras)
    }
}

internal actual suspend fun decodeBitmap(
    options: Options,
    bytes: ByteArray,
): DecodeResult {
    val (srcWidth, srcHeight) = getOriginalSize(bytes)
    val (dstWidth, dstHeight) = DecodeUtils.computeDstSize(
        srcWidth = srcWidth,
        srcHeight = srcHeight,
        targetSize = options.size,
        scale = options.scale,
        maxSize = options.maxBitmapSize,
    )
    var multiplier = DecodeUtils.computeSizeMultiplier(
        srcWidth = srcWidth,
        srcHeight = srcHeight,
        dstWidth = dstWidth,
        dstHeight = dstHeight,
        scale = options.scale,
        maxSize = options.maxBitmapSize,
    )

    // Only upscale the image if the options require an exact size.
    if (options.precision == Precision.INEXACT) {
        multiplier = multiplier.coerceAtMost(1.0)
    }

    val outWidth = (multiplier * srcWidth).toInt()
    val outHeight = (multiplier * srcHeight).toInt()

    val bitmap: Bitmap = decodeImageAsync(bytes, outWidth, outHeight)

    return DecodeResult(
        image = bitmap.asImage(),
        isSampled = bitmap.width < srcWidth || bitmap.height < srcHeight,
    )
}

private fun normalizeBitmap(inBitmap: Bitmap, size: Size): Bitmap {
    // Fast path: if the input bitmap is valid, return it.
    if (isConfigValid(inBitmap, options) && isSizeValid(inBitmap, options, size)) {
        return inBitmap
    }

    // Slow path: re-render the bitmap with the correct size + config.
    val scale = DecodeUtils.computeSizeMultiplier(
        srcWidth = inBitmap.width,
        srcHeight = inBitmap.height,
        dstWidth = size.width.pxOrElse { inBitmap.width },
        dstHeight = size.height.pxOrElse { inBitmap.height },
        scale = options.scale,
        maxSize = options.maxBitmapSize,
    ).toFloat()
    val dstWidth = (scale * inBitmap.width).roundToInt()
    val dstHeight = (scale * inBitmap.height).roundToInt()
    val safeConfig = when {
        SDK_INT >= 26 && options.bitmapConfig == Bitmap.Config.HARDWARE -> Bitmap.Config.ARGB_8888
        else -> options.bitmapConfig
    }

    val paint = Paint(Paint.ANTI_ALIAS_FLAG or Paint.FILTER_BITMAP_FLAG)
    val outBitmap = createBitmap(dstWidth, dstHeight, safeConfig)
    outBitmap.applyCanvas {
        scale(scale, scale)
        drawBitmap(inBitmap, 0f, 0f, paint)
    }
    inBitmap.recycle()

    return outBitmap
}

private fun MediaMetadataRetriever.setDataSource(source: ImageSource) {
    val metadata = source.metadata
    when {
        metadata is MediaSourceMetadata -> {
            setDataSource(metadata.mediaDataSource)
        }

        metadata is AssetMetadata -> {
            options.context.assets.openFd(metadata.filePath).use {
                setDataSource(it.fileDescriptor, it.startOffset, it.length)
            }
        }

        metadata is ContentMetadata -> {
            setDataSource(options.context, metadata.uri.toAndroidUri())
        }

        metadata is ResourceMetadata -> {
            setDataSource("android.resource://${metadata.packageName}/${metadata.resId}")
        }

        source.fileSystem === FileSystem.SYSTEM -> {
            setDataSource(source.file().toFile().path)
        }

        else -> {
            val handle = source.fileSystem.openReadOnly(source.file())
            setDataSource(FileHandleMediaDataSource(handle))
        }
    }
}

@OptIn(KoinInternalApi::class)
fun KoinApplication.androidFileProperties(
    koinPropertyFile: String = "koin.properties",
): KoinApplication {
    val koinProperties = Properties()
    val androidContext = koin.get<Context>()
    try {
        val hasFile = androidContext.assets?.list("")?.contains(koinPropertyFile) ?: false
        if (hasFile) {
            try {
                androidContext.assets.open(koinPropertyFile).use { koinProperties.load(it) }
                val nb = koin.propertyRegistry.saveProperties(koinProperties)
                if (koin.logger.isAt(Level.INFO)) {
                    koin.logger.info("[Android-Properties] loaded $nb properties from assets/$koinPropertyFile")
                }
            } catch (e: Exception) {
                koin.logger.error("[Android-Properties] error for binding properties : $e")
            }
        } else {
            if (koin.logger.isAt(Level.INFO)) {
                koin.logger.info("[Android-Properties] no assets/$koinPropertyFile file to load")
            }
        }
    } catch (e: Exception) {
        koin.logger.error("[Android-Properties] error while loading properties from assets/$koinPropertyFile : $e")
    }
    return this
}

