override fun get(context: ResolutionContext): T {
    if (context.scope.scopeQualifier != beanDefinition.scopeQualifier && context.scopeArchetype != beanDefinition.scopeQualifier) {
        error("Wrong Scope qualifier: trying to open instance for ${context.scope.id} in $beanDefinition")
    }

    // Fast path: check if already created without locking
    val existing = values[context.scope.id]
    if (existing != null) {
        return existing
    }

    // Slow path: need to create the instance with locking
    return KoinPlatformTools.synchronized(this) {
        // Double-check inside lock to avoid race condition
        val doubleCheck = values[context.scope.id]
        if (doubleCheck != null) {
            doubleCheck
        } else {
            if (!holdInstance) {
                throw MissingScopeValueException("No value for scope '${context.scope.id}' in $beanDefinition")
            }
            val created = super.create(context)
            if (holdInstance) {
                values[context.scope.id] = created
            }
            created
        }
    }
}

@KoinInternalApi
fun <T : Any> createDefinition(
    kclass: KClass<T>,
    definition: Definition<T>,
    qualifier: Qualifier? = null,
    scopeQualifier: Qualifier = rootScopeQualifier,
    factoryKind: Kind,
    module: Module,
    createdAtStart: Boolean = false
): KoinDefinition<T> {
    // Explicitly pass secondaryTypes for binary compatibility with Koin 4.1.x and 4.2.x
    val def = BeanDefinition(
        scopeQualifier,
        kclass,
        qualifier,
        definition,
        factoryKind,
        emptyList()  // secondaryTypes - explicit to avoid default parameter bytecode differences
    )
    val factory = when (factoryKind) {
        Kind.Singleton -> SingleInstanceFactory(def)
        Kind.Factory -> FactoryInstanceFactory(def)
        Kind.Scoped -> ScopedInstanceFactory(def)
    }
    module.indexPrimaryType(factory)

    // Handle createdAtStart for singletons
    if (createdAtStart && factoryKind == Kind.Singleton && factory is SingleInstanceFactory<*>) {
        module.eagerInstances.add(factory)
    }

    return KoinDefinition(module, factory)
}

