@Suppress("UNCHECKED_CAST")
    protected fun allocateSlot(): S {
        // Actually create slot under lock
        val subscriptionCount: SubscriptionCountStateFlow?
        val slot = synchronized(this) {
            val slots = when (val curSlots = slots) {
                null -> createSlotArray(2).also { slots = it }
                else -> if (nCollectors >= curSlots.size) {
                    curSlots.copyOf(2 * curSlots.size).also { slots = it }
                } else {
                    curSlots
                }
            }
            var index = nextIndex
            var slot: S
            while (true) {
                slot = slots[index] ?: createSlot().also { slots[index] = it }
                index++
                if (index >= slots.size) index = 0
                if ((slot as AbstractSharedFlowSlot<Any>).allocateLocked(this)) break // break when found and allocated free slot
            }
            nextIndex = index
            nCollectors++
            subscriptionCount = _subscriptionCount // retrieve under lock if initialized
            slot
        }
        // increments subscription count
        subscriptionCount?.increment(1)
        return slot
    }

@FlowPreview
public fun <T> Flow<T>.sample(periodMillis: Long): Flow<T> {
    require(periodMillis > 0) { "Sample period should be positive" }
    return scopedFlow { downstream ->
        val values = produce(capacity = Channel.CONFLATED) {
            collect { value -> send(value ?: NULL) }
        }
        var lastValue: Any? = null
        val ticker = fixedPeriodTicker(periodMillis)
        while (lastValue !== DONE) {
            select<Unit> {
                values.onReceiveCatching { result ->
                    result
                        .onSuccess { lastValue = it }
                        .onFailure {
                            it?.let { throw it }
                            ticker.cancel(ChildCancelledException())
                            lastValue = DONE
                        }
                }

                // todo: shall be start sampling only when an element arrives or sample aways as here?
                ticker.onReceive {
                    val value = lastValue ?: return@onReceive
                    lastValue = null // Consume the value
                    downstream.emit(NULL.unbox(value))
                }
            }
        }
    }
}

internal fun runEventLoop() {
    withScopedMemoryAllocator { allocator ->
        val ptrToSubscription = initializeSubscriptionPtr(allocator)
        val ptrTo32Bytes = allocator.allocate(32)
        val ptrTo8Bytes = allocator.allocate(8)
        val eventLoop = DefaultExecutor
        eventLoop.incrementUseCount()
        try {
            while (true) {
                val parkNanos = eventLoop.processNextEvent()
                if (parkNanos == Long.MAX_VALUE) {
                    // no more events
                    break
                }
                if (parkNanos > 0) {
                    // sleep until the next event
                    sleep(
                        parkNanos,
                        ptrTo32Bytes = ptrTo32Bytes,
                        ptrTo8Bytes = ptrTo8Bytes,
                        ptrToSubscription = ptrToSubscription
                    )
                }
            }
        } finally { // paranoia
            eventLoop.decrementUseCount()
        }
    }
}
